import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { toast } from "react-toastify";

function Enrollments() {
  const user = useSelector((state) => state.auth.user);
  const [courses, setCourses] = useState([]);
  const [enrollments, setEnrollments] = useState([]);
  const [schedules, setSchedules] = useState([]);

  useEffect(() => {
    if (user?.role === "student" && user.classId) {
      fetch(`http://localhost:3001/courses?classId=${user.classId}`)
        .then((res) => res.json())
        .then((data) => setCourses(Array.isArray(data) ? data : []))
        .catch((error) => {
          toast.error("Ошибка загрузки курсов");
          setCourses([]);
        });
      fetch(`http://localhost:3001/enrollments?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setEnrollments(Array.isArray(data) ? data : []))
        .catch((error) => {
          toast.error("Ошибка загрузки записей");
          setEnrollments([]);
        });
      fetch(`http://localhost:3001/schedules?classId=${user.classId}`)
        .then((res) => res.json())
        .then((data) => {
          console.log("Schedules data:", data);
          setSchedules(Array.isArray(data) ? data : []);
        })
        .catch((error) => {
          toast.error("Ошибка загрузки расписания");
          setSchedules([]);
        });
    }
  }, [user]);

  async function handleEnroll(courseId) {
    try {
      if (enrollments.some((e) => e.courseId === courseId)) {
        toast.error("Вы уже записаны на этот курс!");
        return;
      }
      const response = await fetch("http://localhost:3001/enrollments", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          courseId: parseInt(courseId),
        }),
      });
      if (response.ok) {
        const newEnrollment = await response.json();
        setEnrollments([...enrollments, newEnrollment]);
        toast.success("Вы успешно записаны на курс!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Вы записаны на курс "${courses.find((c) => c.id === courseId)?.name}".`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        const errorData = await response.json();
        toast.error(`Не удалось записаться: ${errorData.message || "Ошибка сервера"}`);
      }
    } catch (error) {
      console.error("Enroll error:", error);
      toast.error("Сетевая ошибка при записи на курс");
    }
  }

  async function handleUnenroll(enrollmentId, courseId) {
    try {
      const response = await fetch(`http://localhost:3001/enrollments/${enrollmentId}`, {
        method: "DELETE",
      });
      if (response.ok) {
        setEnrollments(enrollments.filter((e) => e.id !== enrollmentId));
        toast.success("Вы отписались от курса!");
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Вы отписались от курса "${courses.find((c) => c.id === courseId)?.name}".`,
            createdAt: new Date().toISOString(),
          }),
        });
      } else {
        const errorData = await response.json();
        console.error("Unenroll error response:", errorData);
        toast.error(`Не удалось отписаться: ${errorData.message || "Ошибка сервера"}`);
      }
    } catch (error) {
      console.error("Unenroll error:", error);
      toast.error("Сетевая ошибка при отписке от курса");
    }
  }

  if (user?.role !== "student") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  if (!user.classId) {
    return <div className="container mt-5"><h1>У вас не указан класс. Обратитесь к администратору.</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Запись на курсы</h1>
      <div className="row">
        <div className="col-md-6">
          <div className="card shadow mb-4">
            <div className="card-body">
              <h2 className="card-title">Доступные курсы</h2>
              {courses.length === 0 ? (
                <p>Нет доступных курсов для вашего класса</p>
              ) : (
                <ul className="list-group">
                  {courses.map((course) => {
                    const courseSchedules = schedules.filter((s) => s.courseId === course.id && s.classId === user.classId);
                    return (
                      <li key={course.id} className="list-group-item d-flex justify-content-between align-items-center">
                        <div>
                          <strong>{course.name}</strong>
                          {courseSchedules.length > 0 ? (
                            <ul>
                              {courseSchedules.map((schedule) => (
                                <li key={schedule.id}>
                                  Дата: {new Date(schedule.dateTime).toLocaleString()}
                                </li>
                              ))}
                            </ul>
                          ) : (
                            <p>Расписание отсутствует</p>
                          )}
                        </div>
                        <button
                          className="btn btn-primary btn-sm"
                          onClick={() => handleEnroll(course.id)}
                          disabled={enrollments.some((e) => e.courseId === course.id)}
                        >
                          Записаться
                        </button>
                      </li>
                    );
                  })}
                </ul>
              )}
            </div>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title">Ваши записи</h2>
              {enrollments.length === 0 ? (
                <p>Вы не записаны ни на один курс</p>
              ) : (
                <ul className="list-group">
                  {enrollments.map((enrollment) => {
                    const course = courses.find((c) => c.id === enrollment.courseId);
                    return (
                      <li key={enrollment.id} className="list-group-item d-flex justify-content-between align-items-center">
                        <span>{course?.name || "Неизвестный курс"}</span>
                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => handleUnenroll(enrollment.id, enrollment.courseId)}
                        >
                          Отписаться
                        </button>
                      </li>
                    );
                  })}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Enrollments;
